class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable now returns null
        // for empty env vars on Unix instead of "". Use DoesEnvironmentVariableExist
        // to distinguish "not set" from "set to empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (!Environment.DoesEnvironmentVariableExist("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

